import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import { 
  obtenerCarritoAPI, 
  agregarAlCarritoAPI, 
  eliminarDelCarritoAPI, 
  vaciarCarritoAPI,
  haySesionActiva
} from '../servicios/api';

const CarritoContexto = createContext(null);

export function CarritoProvider({ children }) {
  const [carrito, setCarrito] = useState([]);
  const [cargando, setCargando] = useState(false);

  // Sincronizar con el servidor
  const sincronizar = useCallback(async () => {
    if (!haySesionActiva()) {
      setCarrito([]); // O manejar carrito de invitados si se desea
      return;
    }

    try {
      setCargando(true);
      const data = await obtenerCarritoAPI();
      setCarrito(data || []);
    } catch (error) {
      console.error('Error al sincronizar carrito:', error);
    } finally {
      setCargando(false);
    }
  }, []);

  // Cargar al inicio
  useEffect(() => {
    sincronizar();
  }, [sincronizar]);

  const agregarItem = useCallback(async (productoId, cantidad = 1) => {
    if (!haySesionActiva()) {
      alert('Debes iniciar sesión para agregar productos al carrito.');
      return;
    }
    try {
      await agregarAlCarritoAPI(productoId, cantidad);
      await sincronizar();
    } catch (error) {
      alert(error.message);
    }
  }, [sincronizar]);

  const eliminarItem = useCallback(async (itemId) => {
    try {
      await eliminarDelCarritoAPI(itemId);
      await sincronizar();
    } catch (error) {
      console.error(error);
    }
  }, [sincronizar]);

  const vaciarCarrito = useCallback(async () => {
    try {
      await vaciarCarritoAPI();
      setCarrito([]);
    } catch (error) {
      console.error(error);
    }
  }, []);

  return (
    <CarritoContexto.Provider value={{ carrito, cargando, agregarItem, eliminarItem, vaciarCarrito, sincronizar }}>
      {children}
    </CarritoContexto.Provider>
  );
}

export function useCarrito() {
  const context = useContext(CarritoContexto);
  if (!context) throw new Error('useCarrito debe usarse dentro de CarritoProvider');
  return context;
}
